from openpyxl import Workbook
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from openpyxl.utils import get_column_letter
from pathlib import Path

wb = Workbook()

HDR_FILL  = PatternFill("solid", start_color="1F3864")
ALT_FILL  = PatternFill("solid", start_color="EBF0FA")
YELL_FILL = PatternFill("solid", start_color="FFF2CC")
RED_FILL  = PatternFill("solid", start_color="FCE4D6")
GRN_FILL  = PatternFill("solid", start_color="E2EFDA")
BLUE_FILL = PatternFill("solid", start_color="DDEEFF")
HDR_FONT  = Font(name="Arial", bold=True, color="FFFFFF", size=9)
BODY_FONT = Font(name="Arial", size=9)
BOLD_FONT = Font(name="Arial", bold=True, size=9)
THIN = Side(style="thin", color="BFBFBF")
BOX  = Border(left=THIN, right=THIN, top=THIN, bottom=THIN)
WRAP = Alignment(wrap_text=True, vertical="top")

def style_header_row(ws, row_num, num_cols):
    for col in range(1, num_cols+1):
        c = ws.cell(row=row_num, column=col)
        c.fill = HDR_FILL; c.font = HDR_FONT; c.alignment = WRAP; c.border = BOX

def style_data_row(ws, row_num, num_cols, alt=False, fill=None):
    for col in range(1, num_cols+1):
        c = ws.cell(row=row_num, column=col)
        c.font = BODY_FONT; c.alignment = WRAP; c.border = BOX
        if fill: c.fill = fill
        elif alt: c.fill = ALT_FILL

def set_col_widths(ws, widths):
    for i, w in enumerate(widths, 1):
        ws.column_dimensions[get_column_letter(i)].width = w

def write_row(ws, row_num, values):
    for col, val in enumerate(values, 1):
        ws.cell(row=row_num, column=col, value=val)

