ws5 = wb.create_sheet("Instructions_and_Glossary")

def write_section_header(ws, row, text):
    ws.cell(row=row, column=1, value=text)
    ws.cell(row=row, column=1).font = Font(name="Arial", bold=True, size=11, color="FFFFFF")
    ws.cell(row=row, column=1).fill = HDR_FILL
    ws.cell(row=row, column=1).alignment = Alignment(wrap_text=True, vertical="top")
    ws.merge_cells(start_row=row, start_column=1, end_row=row, end_column=4)

def write_body(ws, row, text, col=1, span=4):
    ws.cell(row=row, column=col, value=text)
    ws.cell(row=row, column=col).font = BODY_FONT
    ws.cell(row=row, column=col).alignment = Alignment(wrap_text=True, vertical="top")
    if span > 1:
        ws.merge_cells(start_row=row, start_column=col, end_row=row, end_column=col+span-1)

r = 1
write_section_header(ws5, r, "A. HOW TO READ AND USE THIS RCM"); r+=1
write_body(ws5, r, """This Risk and Control Matrix (RCM) is structured for a mid-sized UK bank operating under PRA and FCA dual regulation. It covers eight process areas with 60+ controls mapped to UK-specific regulatory obligations.

RCM_Master: The primary control register. Each row represents one control within one process. Read across the row to understand the obligation driving the control, the risk it addresses, how it operates, who is accountable (including the SMCR SMF holder), what evidence it generates, and its current effectiveness.

Regulatory_Obligation_Register: The canonical source of UK regulatory obligations. Each obligation is cited to a specific UK regulatory instrument with the exact reference. This register is the source for the Regulatory_Obligation_Ref column in RCM_Master.

UK_KRI_Library: Leading and lagging indicators linked to specific risk areas and SMF holders. KRIs are designed to provide early warning of control effectiveness degradation before a regulatory event occurs.

SMCR_Accountability_Matrix: Maps every Senior Management Function to their prescribed responsibilities, the processes they are accountable for, and the evidence required to demonstrate reasonable steps under FSMA 2000 s.66A.

COLOUR CODING — RCM_Master:
  Green rows: Controls rated Effective
  Yellow rows: Controls rated Effective with Observations (action required)
  Red/Orange rows: Controls rated Needs Improvement (material finding or open issue)
  Blue/white alternating: No effectiveness data or not applicable"""); r+=1

write_section_header(ws5, r, "B. UK REGULATORY REFERENCE GUIDE"); r+=1
write_body(ws5, r, """PRIMARY SOURCES (always use for citation):
  FCA Handbook: https://www.handbook.fca.org.uk
  PRA Rulebook: https://www.prarulebook.co.uk
  Legislation.gov.uk (for FSMA, MLR, PSRs, etc.): https://www.legislation.gov.uk
  FCA Final Notices: https://www.fca.org.uk/news/final-notices
  PRA Supervisory Statements: https://www.bankofengland.co.uk/prudential-regulation
  FCA Consumer Duty resources: https://www.fca.org.uk/firms/consumer-duty
  OFSI Consolidated UK Sanctions List: https://www.gov.uk/government/collections/financial-sanctions-regime-specific-legislation
  Companies House API (PSC register): https://developer.company-information.service.gov.uk
  NCA goAML portal (for SAR/DAML submissions): https://www.nationalcrimeagency.gov.uk/
  ICO (UK GDPR, DPA 2018): https://ico.org.uk

KEY INSTRUMENTS IN THIS RCM:
  MLR 2017: Money Laundering, Terrorist Financing and Transfer of Funds (Information on the Payer) Regulations 2017 (SI 2017/692)
  POCA 2002: Proceeds of Crime Act 2002
  FSMA 2000: Financial Services and Markets Act 2000 (as amended including FSMA 2023)
  PS22/9 (Consumer Duty): FCA Policy Statement — A New Consumer Duty (PS22/9, July 2022)
  PS21/3 (Operational Resilience): FCA/PRA Policy Statement — Operational Resilience (PS21/3, March 2021)
  SS1/21: PRA Supervisory Statement — Operational Resilience (SS1/21, March 2021)
  SS2/21: PRA Supervisory Statement — Outsourcing and Third-Party Risk (SS2/21, March 2021)
  SS1/23: PRA Supervisory Statement — Model Risk Management (SS1/23, May 2023, effective 17 May 2024)
  PSR PS23/3: PSR Policy Statement — APP Fraud Reimbursement (PS23/3, effective 7 October 2024)
  ECTEA 2022: Economic Crime (Transparency and Enforcement) Act 2022
  UK-MiFIR: UK Markets in Financial Instruments Regulation (SI 2017/701 as retained and amended)
  UK-EMIR: UK European Market Infrastructure Regulation (SI 2013/504 as retained and amended)
  JMLSG: Joint Money Laundering Steering Group Guidance (Parts I and II, updated periodically — court-persuasive)"""); r+=1

write_section_header(ws5, r, "C. GLOSSARY — UK BANKING AND REGULATORY TERMS"); r+=1

gloss_header = ["Term", "Definition", "Source Instrument"]
write_row(ws5, r, gloss_header)
style_header_row(ws5, r, 3); r+=1

glossary = [
["APP Fraud","Authorised Push Payment Fraud — fraud where a customer is deceived into authorising a payment to a fraudster's account; sending and receiving PSPs are jointly liable under PSR PS23/3 (effective October 2024)","PSR PS23/3"],
["Accountability Controls","Controls that document the judgement exercised by a named Senior Manager over the control environment in their area of responsibility; the fourth control type unique to the UK SMCR framework","FSMA 2000 s.66A; derived from Reasonable Steps doctrine"],
["ARM (Approved Reporting Mechanism)","A firm approved by the FCA to report transaction details to the FCA on behalf of investment firms under UK-MiFIR; examples include DTCC and UnaVista","UK-MiFIR Art.26"],
["Bank of England (BoE)","The UK's central bank; responsible for financial stability, the CHAPS payment system, and macro-prudential regulation through the Financial Policy Committee","Bank of England Act 1998"],
["BRC (Board Risk Committee)","Board-level committee responsible for overseeing the firm's risk management framework; receives reports from the CRO and challenges risk appetite and KRI performance","PRA Corporate Governance requirements; SMCR SMF10"],
["Certification Regime","The SMCR requirement for firms to assess and certify annually that individuals in Significant Harm Functions are fit and proper to perform their role","FSMA 2000 s.63F; FCA SYSC 10A"],
["CHAPS","Clearing House Automated Payment System — the UK's high-value sterling real-time gross settlement payment system operated by the Bank of England; subject to Operational Resilience Impact Tolerance requirements under PS21/3","Bank of England RTGS system"],
["COCON","FCA Conduct Rules Sourcebook — contains the Individual Conduct Rules (IC1-IC6) and Senior Manager Conduct Rules (SC1-SC4) that apply to SMCR in-scope individuals","FCA Handbook COCON"],
["Confirmation of Payee (CoP)","A UK-specific account name checking service that verifies whether the name provided by a payment initiator matches the name of the account holder at the receiving bank; mandatory for in-scope PSPs","PSR Direction PSD2/1; CoP Scheme Rules"],
["Consumer Duty","FCA's overarching duty for retail financial services firms to act to deliver good outcomes for retail customers across four outcomes: Products and Services, Price and Value, Consumer Understanding, and Consumer Support","FCA PS22/9; PRIN 12"],
["CTP (Critical Third Party)","A third-party service provider designated by HM Treasury under FSMA 2023 Part 6A as a provider of systemic services to UK financial institutions; subject to direct PRA/FCA oversight; AWS UK was designated from March 2025","FSMA 2023 Part 6A"],
["CDD (Customer Due Diligence)","The process of identifying and verifying the identity of customers, beneficial owners and the purpose of business relationships; required under MLR 2017; comprises standard CDD and Enhanced Due Diligence (EDD)","MLR 2017 Reg 28-33"],
["DAML (Defence Against Money Laundering)","A consent request submitted to the NCA under POCA 2002 s.336 before conducting a transaction that the firm suspects may relate to the proceeds of crime; creates a 7-day notice window and 31-day moratorium","POCA 2002 s.335-336"],
["DPA 2018","Data Protection Act 2018 — the UK's primary data protection legislation supplementing UK GDPR; contains UK-specific provisions including financial crime prevention exemptions in Schedule 2","Data Protection Act 2018"],
["EDD (Enhanced Due Diligence)","Heightened customer due diligence required for high-risk situations including PEPs, customers from HMT high-risk third countries, and other high-risk situations identified by the firm","MLR 2017 Reg 33-35"],
["EMIR (European Market Infrastructure Regulation)","Regulation requiring the reporting of OTC and ETD derivative contracts to trade repositories; as retained in UK law (UK-EMIR); REFIT amendments effective April 2024 in the UK significantly changed reporting field requirements","UK SI 2013/504 as retained and amended"],
["eIDV (Electronic Identity Verification)","Automated verification of a customer's identity using electronic data sources including credit bureau data, electoral roll, HMLR records and biometric liveness checks; used as an alternative to documentary verification","MLR 2017 Reg 28; JMLSG Guidance"],
["F&P (Fitness and Propriety)","Assessment of whether an individual is suitable to perform a Senior Management Function or Certified Person role; covers honesty/integrity, competence/capability, and financial soundness","FSMA 2000 s.63F; FCA FIT sourcebook"],
["Fair Value Assessment (FVA)","Annual structured assessment required under Consumer Duty (PS22/9) to determine whether a retail product delivers fair value — whether the price charged is reasonable relative to the benefits delivered to the target market","FCA PS22/9 Chapter 5 — Price and Value Outcome"],
["FCA","Financial Conduct Authority — the UK's conduct regulator for financial services firms; responsible for consumer protection, market integrity, and competition; co-regulator with PRA for dual-regulated firms","Financial Services Act 2012"],
["FOS","Financial Ombudsman Service — the independent body that adjudicates customer complaints against financial services firms; firms are bound by FOS decisions up to the applicable award limit; FOS jurisdiction is triggered if the firm fails to respond to a complaint within 8 weeks","FSMA 2000 Part XVI; DISP"],
["FPS (Faster Payments Service)","The UK's real-time retail payments system enabling instant payments up to the applicable limit; operated by Pay.UK; subject to Operational Resilience requirements as an IBS for participating banks","PSR; Pay.UK Faster Payments Rules"],
["FIRDS","Financial Instruments Reference Data System — FCA's reference data system for financial instruments reportable under UK-MiFIR; used for validating ISIN and instrument identifiers in transaction reports","UK-MiFIR; FCA FIRDS guidance"],
["ICAAP","Internal Capital Adequacy Assessment Process — the firm's own annual assessment of the capital it needs to hold to support all its risks; submitted to PRA and used as the basis for determining the firm's Pillar 2A capital add-on","PRA Rulebook; PRA SS18/14"],
["ICO","Information Commissioner's Office — the UK's data protection regulator; supervises compliance with UK GDPR and DPA 2018; has powers to fine firms up to £17.5m or 4% of global turnover for serious data protection breaches","Data Protection Act 2018"],
["IBS (Important Business Service)","A service provided to external end users whose disruption would cause intolerable harm to consumers or other market participants; firms must identify their IBSs, set impact tolerances, and test against severe-but-plausible scenarios under PS21/3","PRA/FCA PS21/3; SS1/21"],
["Impact Tolerance","The maximum tolerable level of disruption to an Important Business Service, measured in appropriate units (e.g. time, number of transactions); set by the board and tested against in scenario exercises","PRA/FCA PS21/3 para 2.10-2.16"],
["ISO 20022","An international standard for electronic financial messaging; CHAPS completed its ISO 20022 migration under the Bank of England RTGS Renewal Programme; UK-EMIR REFIT introduced ISO 20022 for derivatives reporting from April 2024","Bank of England RTGS Renewal; UK-EMIR REFIT"],
["JMLSG","Joint Money Laundering Steering Group — industry body that produces guidance on the prevention of money laundering and terrorist financing; JMLSG Guidance is court-persuasive in the UK and the FCA expects firms to follow it unless they have a justified reason not to","MLR 2017; JMLSG Parts I and II"],
["KRI (Key Risk Indicator)","A metric that provides early warning of an increase in exposure to risk; ideally leading (predicting a future control failure) rather than lagging (measuring a past failure); linked to SMF accountability under SMCR","PRA/FCA risk management expectations; SMCR"],
["LEI (Legal Entity Identifier)","A 20-character alphanumeric code that uniquely identifies a legal entity participating in financial transactions; required for transaction reporting under UK-MiFIR and UK-EMIR; LEIs expire annually if not renewed","UK-MiFIR; UK-EMIR; GLEIF"],
["MLRO","Money Laundering Reporting Officer — the FCA-approved Nominated Officer responsible for receiving internal suspicious activity reports, making SAR/DAML decisions, and producing the annual MLRO Report to the board; must hold SMF17 approval","MLR 2017 Reg 21; SYSC 6.3.7G"],
["MRM (Management Responsibilities Map)","A document maintained by a dual-regulated firm showing all Senior Management Functions, the individuals holding them, their prescribed responsibilities and reporting lines; filed with FCA/PRA and updated on material change","FSMA 2000 s.60A; FCA SUP 10C.12R"],
["NCA","National Crime Agency — the UK's lead agency for serious and organised crime including money laundering; receives Suspicious Activity Reports (SARs) and Defence Against Money Laundering (DAML) applications from regulated firms","Serious Organised Crime and Police Act 2005; POCA 2002"],
["OFSI","Office of Financial Sanctions Implementation — the HM Treasury body responsible for implementing the UK's financial sanctions regime; firms must comply with OFSI Consolidated List and report frozen assets quarterly; strict liability for breaches under ECTEA 2022","Economic Crime (Transparency and Enforcement) Act 2022"],
["PEP (Politically Exposed Person)","An individual who holds or has held a prominent public function, their family members, and known close associates; UK includes both domestic and foreign PEPs; EDD required under MLR 2017 Reg 35; proportionality guidance in FCA FG17/6","MLR 2017 Reg 35; FCA FG17/6"],
["POCA 2002","Proceeds of Crime Act 2002 — the primary UK anti-money laundering statute; creates criminal offences for money laundering (s.327-329), failure to disclose (s.330), and the DAML consent mechanism (s.335-336)","Proceeds of Crime Act 2002"],
["PRA","Prudential Regulation Authority — part of the Bank of England; responsible for the prudential regulation of banks, building societies, credit unions, insurers and investment firms; supervises the safety and soundness of regulated firms","Financial Services Act 2012; Bank of England Act 1998"],
["Prescribed Responsibilities (PR)","Specific regulatory responsibilities that must be allocated to named SMF holders by dual-regulated firms; examples include PR-F (SMCR Compliance Oversight), PR-G (Whistleblowing), PR-H (Consumer Duty); Consumer Duty-specific PRs added in 2023","FCA SUP 10C; PRA Senior Managers Regime"],
["PSC Register (People with Significant Control)","The UK's register of beneficial owners of companies, maintained by Companies House; firms with UK corporate customers must consult the PSC register as part of their beneficial owner identification process under MLR 2017 Reg 29","Companies Act 2006 as amended; MLR 2017 Reg 29"],
["PSR","Payment Systems Regulator — the economic regulator for payment systems in the UK; responsible for the APP fraud reimbursement regime under PS23/3; regulates access to payment systems and promotes competition","Financial Services (Banking Reform) Act 2013; PSR PS23/3"],
["PSRs 2017","Payment Services Regulations 2017 — the UK implementation of PSD2; covers payment service provider obligations including Strong Customer Authentication, transaction authorisation, refund rights, and execution timeframes","SI 2017/752 Payment Services Regulations 2017"],
["Reasonable Steps","The standard under FSMA 2000 s.66A against which an SMF holder's conduct is assessed when a regulatory breach occurs in their area of responsibility; the SMF will not be guilty of misconduct if they took such steps as a person in their position could reasonably be expected to take to avoid the breach","FSMA 2000 s.66A; FCA enforcement decisions"],
["REP008","The FCA form used to notify the FCA of a Conduct Rule breach by an SMF holder or Certified Person; must be submitted within 7 business days of the firm concluding that a breach has occurred","FCA COCON 9; FCA SUP 15.11"],
["Ring-Fencing","UK structural reform requiring banks with core deposits above the threshold (£35 billion following Edinburgh Reforms 2022) to separate retail banking activities (Ring-Fenced Body) from wholesale/investment banking (Non-Ring-Fenced Body)","FSMA 2000 Part 9B; Banking Reform Act 2013"],
["SAR (Suspicious Activity Report)","A report filed by the firm's Nominated Officer to the NCA via the goAML portal where the firm has knowledge or reasonable grounds to suspect that another person is engaged in money laundering; filing a SAR provides a legal defence against POCA money laundering offences","POCA 2002 s.330; JMLSG Guidance"],
["SCA (Strong Customer Authentication)","A regulatory requirement under PSRs 2017 Reg 100 to authenticate electronic payment transactions using at least two of: knowledge (PIN/password), possession (mobile device/OTP), or inherence (biometric); includes specified exemptions","PSRs 2017 Reg 100; FCA SCA-RTS"],
["SICR","Significant Increase in Credit Risk — the IFRS 9 criterion that triggers migration of a credit facility from Stage 1 to Stage 2; results in provisioning for lifetime expected credit losses rather than 12-month ECL","IFRS 9 IASB standard (as adopted in UK)"],
["SM&CR / SMCR","Senior Managers and Certification Regime — the UK accountability regime introduced under FSMA 2000 (as amended) requiring pre-approval of Senior Management Functions, annual F&P certification of Certified Persons, and application of Conduct Rules to all in-scope staff","FSMA 2000 ss.59-71A; FCA SUP 10C; PRA Senior Managers Regime"],
["SMF (Senior Management Function)","A specific role at a firm that requires FCA and/or PRA pre-approval; examples include SMF1 (CEO), SMF4 (CRO), SMF16 (CCO), SMF17 (MLRO); each SMF holder must have a Statement of Responsibilities","FSMA 2000 s.59; FCA SUP 10C; PRA Rulebook"],
["SoR (Statement of Responsibilities)","A personal document for each SMF holder setting out the aspects of the firm's affairs for which they are responsible; must be filed with FCA/PRA at appointment and on any material change; the primary SMCR personal accountability document","FSMA 2000 s.60; FCA SUP 10C.11R"],
["STOR (Suspicious Transaction and Order Report)","A report submitted to the FCA via the GABRIEL portal where a firm has reasonable grounds to suspect that a transaction or order may involve market abuse; must be submitted as soon as reasonably practicable","UK MAR Art.16; FCA MAR 1"],
["s.166 (Skilled Persons Review)","A review conducted under FSMA 2000 s.166 by a skilled person appointed by the firm but approved by the FCA/PRA; the regulator sets the scope; the firm pays; the skilled person reports to the regulator; used when the regulator has concerns about a firm's activities or controls","FSMA 2000 s.166"],
["Three Lines of Defence (3LoD)","The standard model for organising risk management: First Line (business functions owning and operating controls); Second Line (risk and compliance providing oversight and challenge); Third Line (internal audit providing independent assurance)","PRA SS5/21; FCA SYSC guidance"],
["TM (Transaction Monitoring)","Automated systems that monitor customer transactions and generate alerts when patterns match AML typology rules or statistical anomalies; an ongoing monitoring obligation under MLR 2017 Reg 14","MLR 2017 Reg 14; SYSC 6.3.1R"],
["UK GDPR","The UK's retained version of the EU General Data Protection Regulation, amended by the Data Protection, Privacy and Electronic Communications (Amendments etc.) (EU Exit) Regulations 2019; applies to all personal data processing by UK controllers","UK GDPR (retained EU law); DPA 2018"],
["Vulnerable Customer","A customer who, due to their personal circumstances, is especially susceptible to harm — particularly when a firm is not acting with appropriate levels of care; the FCA's definition encompasses customers with health conditions, life events, financial resilience issues, and low capability","FCA FG21/1 — Guidance for Firms on the Fair Treatment of Vulnerable Customers"],
]

for i, row in enumerate(glossary, r):
    for col, val in enumerate(row, 1):
        c = ws5.cell(row=i, column=col, value=val)
        c.font = BODY_FONT; c.alignment = WRAP; c.border = BOX
        if col == 1: c.font = BOLD_FONT
        if i % 2 == 0: c.fill = ALT_FILL

r += len(glossary) + 1
write_section_header(ws5, r, "D. HOW THIS RCM MAPS TO THE FOUNDATIONAL MODEL DOCUMENT"); r+=1
write_body(ws5, r, """The Foundational Model (RCM_Baseline_MidSized_UKBankv1.md) describes six conceptual layers (Regulation → Obligation → Risk → Control → Process → Activity). This RCM operationalises those layers as follows:

  Regulation: The regulatory instruments referenced in Regulatory_Instrument and Regulatory_Body columns
  Obligation: Each row in the Regulatory_Obligation_Register corresponds to one atomic obligation from the foundational model
  Risk: The Risk_ID, Risk_Category_L1, Risk_Category_L2 and Risk_Description columns
  Control: The Control_ID through AI_Automation_Potential columns (the core control specification)
  Process: The Process_ID, Process_Name and Process_Category columns
  Activity: The Control_Description and Designed_Condition columns describe the atomic activity that constitutes control operation

The SMCR_Accountability_Matrix adds the fifth dimension unique to UK banking — personal accountability — linking every control to the SMF holder who bears statutory personal liability under FSMA 2000 s.66A.

The Consumer_Duty_Outcome column in RCM_Master maps retail-facing controls to the four Consumer Duty outcomes from PS22/9, implementing the foundational model's requirement that outcomes evidence be linked to control operation."""); r+=1

write_section_header(ws5, r, "E. DATA MODEL MAPPING"); r+=1
write_body(ws5, r, """PLATFORM ENTITY → RCM_Master COLUMN MAPPING:
  PROCESS entity: Process_ID, Process_Name, Process_Category, Process_Owner_Role, IBS_Link, Ring_Fence_Applicable
  CONTROL entity: Control_ID, Control_Name, Control_Type, Control_Sub_Type, Control_Position, Control_Description, Designed_Condition, Operating_Frequency, Current_Effectiveness_Rating
  OBLIGATION entity: Regulatory_Obligation_Ref, Regulatory_Instrument, Regulatory_Body, Obligation_Type (see full detail in Regulatory_Obligation_Register)
  RISK entity: Risk_ID, Risk_Category_L1, Risk_Category_L2, Risk_Description, Inherent_Risk_Rating
  SMF_HOLDER entity: SMF_Accountable (see full detail in SMCR_Accountability_Matrix)
  EVIDENCE entity: Evidence_Type, Evidence_System
  ISSUE entity: Open_Issue_Flag (issue details maintained in separate Issues Register)
  KRI entity: KRI_Name, KRI_Green_Threshold, KRI_Amber_Threshold, KRI_Red_Threshold (see full detail in UK_KRI_Library)
  CONSUMER_OUTCOME entity: Consumer_Duty_Outcome
  IMPORTANT_BUSINESS_SERVICE entity: IBS_Link
  OBLIGATION_SOURCE entity: Post_Brexit_Change_Flag (linked to Regulatory_Obligation_Register Post_Brexit_Divergence_from_EU column)"""); r+=1

write_section_header(ws5, r, "F. KNOWN LIMITATIONS AND RECOMMENDED FIRST-PHASE AUTOMATION TARGETS"); r+=1
write_body(ws5, r, """KNOWN LIMITATIONS OF THIS RCM VERSION (v1.0):
  1. Point-in-time snapshot: This RCM reflects the UK regulatory environment as at April 2026. Consumer Duty, EMIR REFIT, CTP regime, and PSR APP fraud reimbursement rules have all changed materially in 2024-2025 and will continue to evolve.
  2. Mid-sized bank profile: Controls are calibrated for a mid-sized UK bank (Category 2-3 PRA firm with £10-50bn balance sheet). Smaller firms will find some controls over-engineered; larger G-SIBs will require additional controls not present here.
  3. Ring-fencing applicability: Ring-fencing controls (CTL-OPR-005, KRI-RFB series) apply only to banks above the £35 billion core deposits threshold. Firms below this threshold should mark these as 'Not Applicable'.
  4. Offshore captive operations: The RCM acknowledges the offshore captive reality in the Process Owner and Frontline Executive personas but does not model the specific evidence standards required for offshore-executed UK-regulated controls as separate control rows. This is a recommended extension in v1.1.
  5. EMIR REFIT remediation: As noted in CTL-CAP-002, UK EMIR REFIT field completeness is an active remediation area at many banks. The Needs Improvement effectiveness rating reflects the industry state as at Q4 2025; expected to improve through 2026.

RECOMMENDED FIRST-PHASE AUTOMATION TARGETS (by AI_Automation_Potential = High):
  1. CTL-ONB-001 / CTL-ONB-002: eIDV and sanctions/PEP screening — already automated at most firms; focus on evidence ingestion and alert-to-case routing automation
  2. CTL-PAY-001 / CTL-PAY-002: CoP result logging and sanctions screening result capture — real-time evidence pre-aggregation for PSR and OFSI regulatory requests
  3. CTL-AML-001: TM model performance monitoring — automated model performance dashboards replacing quarterly manual compilation
  4. CTL-AML-003: DAML consent clock management — automated hold management and Day 4/6 alert generation with SMF17 notification
  5. CTL-COM-002: DISP 8-week SLA monitoring — automated escalation with amber/red flag workflow to reduce breach rate
  6. CTL-SMC-006: SMF assurance pack population — automated KRI data pulls and evidence pre-aggregation to reduce SMF pack preparation time
  7. CTL-OPR-001: IBS dependency map currency monitoring — reconciliation of live system telemetry against documented dependency maps to detect staleness
  8. CTL-CAP-001: MiFIR pre-submission validation — LEI expiry monitoring and automated field validation integrated into ARM submission workflow"""); r+=1

ws5.column_dimensions["A"].width = 20
ws5.column_dimensions["B"].width = 80
ws5.column_dimensions["C"].width = 35
ws5.column_dimensions["D"].width = 30

for row_num in range(1, r+1):
    ws5.row_dimensions[row_num].height = 15

